import React,{ useCallback, useEffect, useState } from 'react'
import { MaplibreProps } from "./Map.types"
import maplibregl,{ 
    Map as MaplibreMap,
    MapLibreEvent,
    MapMouseEvent, 
} from "maplibre-gl"
import { 
    pointsRendering,
    linesRendering,
    popupsRendering,
    circlesRendering,
    rectanglesRendering 
} from "./../../util/render"
import * as Fire from "./../../constant/fire"
import 'maplibre-gl/dist/maplibre-gl.css';


const MAX_ZOOM = 21.99999999999

interface Geometry {
    coordinates:[number,number],
    type:string
}

const Maplibre = ({
    option,
    controls,
    points,
    circles,
    rectangles,
    lines,
    popups,
    children,
    poiHoverEnabled,
    defaultCursorIcon,
    onRenderingComplete,
    onPointsRenderingComplete,
    onLinesRenderingComplete,
    onCirclesRenderingComplete,
    onPopupsRenderingComplete,
    onMapClick,
    onMapContextMenu,
    onMapDoubleClick,
    onMapDragStart,
    onMapDragEnd,
    onMapLoad,
    onMapMoveEnd,
    style,
    className,
    easeTo,
    bound,
    flyTo
}:MaplibreProps) => {
    const [maplibreMap,setMaplibreMap] = useState<MaplibreMap>()
    const [isStyleLoaded,setIsStyleLoaded] = useState<boolean>(false)
    const [isMapLoaded,setIsMapLoaded] = useState<boolean>(false)

    const mapContainerRef = useCallback((node: HTMLDivElement) => {
        if (!node) return

        const map = new maplibregl.Map({
            container: node,
            style: option.style,
            center: option.center,
            zoom: option.zoom,
            maxZoom: 19.9999
        });

        if(defaultCursorIcon){
            map.getCanvas().style.cursor = defaultCursorIcon
        }

        if(controls?.fullScreen){
            map.addControl(new maplibregl.FullscreenControl({ container: node }));
        }

        if(controls?.navigation?.enabled){
            map.addControl(new maplibregl.NavigationControl(controls.navigation.options))
        }

        if(controls?.geolocation?.enabled){
            map.addControl(new maplibregl.GeolocateControl(controls.geolocation.options))
        }

        map.once("load",(ev:MapLibreEvent)=>{
            if(onMapLoad){
                onMapLoad(ev)
            }
            setIsMapLoaded(true)
        })

        map.on("dragstart",(ev)=>{
            if(onMapDragStart){
                onMapDragStart(ev,map)
            }
        })

        map.on("dragend",(ev)=>{
            if(onMapDragEnd){
                onMapDragEnd(ev,map)
            }
        })

        if(poiHoverEnabled){
            map.on("mousemove","F_Land_Fill",(ev:MapMouseEvent)=>{
                const features = map.queryRenderedFeatures(ev.point)
                if(features.length <= 0) return
                if(!features[0].properties.NAME) return

                if(map.getZoom() >= (features[0].layer.minzoom || 0) && map.getZoom() <= ( features[0].layer.maxzoom || MAX_ZOOM )){
                    map.getCanvas().style.cursor = 'pointer'
                    map.on('mouseleave',features[0].layer.id, (ev:MapMouseEvent) => {
                        map.getCanvas().style.cursor = ''
                    })  
                }
            })
    
            map.on("mousemove",(ev:MapMouseEvent)=>{
                const features = map.queryRenderedFeatures(ev.point)
                if(features.length <= 0) return
                if(features[0].layer.type != "symbol") return
                if(!features[0].properties.NAME) return

                const poiGeometry:Geometry = features[0].geometry as Geometry
    
                if(poiGeometry.type != "Point") return

                if(map.getZoom() >= (features[0].layer.minzoom || 0) && map.getZoom() <= ( features[0].layer.maxzoom || MAX_ZOOM )){
                    map.getCanvas().style.cursor = 'pointer'
                    map.on('mouseleave',features[0].layer.id, (ev:MapMouseEvent) => {
                        map.getCanvas().style.cursor = ''
                    })  
                }
            })
        }

        map.once("styledata",()=>{
            setIsStyleLoaded(true)
        })

        if(option.dragRotateDisable){
            map.dragRotate.disable();
        }

        if(option.touchZoomRotateDisable){
            map.touchZoomRotate.disableRotation();
        }

        setMaplibreMap(map)

        return () => {
            maplibreMap?.remove();
        }
    }, []);


    useEffect(()=>{
        if(!points || !maplibreMap || !isStyleLoaded) return
        pointsRendering(points,maplibreMap)
        
        if(onPointsRenderingComplete){
            onPointsRenderingComplete(maplibreMap)
        }
    },[points,isStyleLoaded])

    useEffect(()=>{
        if(!lines || !maplibreMap || !isStyleLoaded) return

        linesRendering(lines,maplibreMap)

        if(onLinesRenderingComplete){
            onLinesRenderingComplete(maplibreMap)
        }
    },[lines,isStyleLoaded])

    useEffect(()=>{
        if(!circles || !maplibreMap || !isStyleLoaded) return

        circlesRendering(circles,maplibreMap)
        
        if(onCirclesRenderingComplete){
            onCirclesRenderingComplete(maplibreMap)
        }
    },[circles,isStyleLoaded])

    useEffect(()=>{
        if(!popups || !maplibreMap || !isStyleLoaded) return

        popupsRendering(popups,maplibreMap)
        
        if(onPopupsRenderingComplete){
            onPopupsRenderingComplete(maplibreMap)
        }
    },[popups,isStyleLoaded])

    useEffect(()=>{
        if(!rectangles || !maplibreMap || !isStyleLoaded) return

        rectanglesRendering(rectangles,maplibreMap)
    },[rectangles,isStyleLoaded])

    useEffect(()=>{
        maplibreMap?.flyTo({
            center:option.center,
            zoom: option.zoom
        })
    },[option.center,option.zoom])

    useEffect(()=>{
        if(!bound) return
        maplibreMap?.fitBounds(bound.coordinates,bound.option,bound.eventData)
    },[bound])

    useEffect(()=>{           
        maplibreMap?.setStyle(option.style)
    },[option.style])

    useEffect(()=>{ 
        if(!easeTo) return
        maplibreMap?.easeTo(easeTo)
    },[easeTo])

    useEffect(()=>{
        if(!flyTo) return
        maplibreMap?.flyTo(flyTo.options,flyTo.eventData)
    },[flyTo])

    useEffect(()=>{
        if(!onMapMoveEnd || !isMapLoaded) return
        maplibreMap.fire("removeMoveend")
        maplibreMap.on("moveend",(ev:MapLibreEvent)=>{onMapMoveEnd(ev,maplibreMap)})
        maplibreMap.on("removeMoveend",()=>{
            maplibreMap.off("moveend",(ev:MapLibreEvent)=>{onMapMoveEnd(ev,maplibreMap)})
        })
    },[onMapMoveEnd,isMapLoaded])

    useEffect(()=>{
        if(!onMapClick || !isMapLoaded) return
        maplibreMap.fire("removeClick")
        maplibreMap.on("click",(ev:MapMouseEvent)=>{onMapClick(ev,maplibreMap)})
        maplibreMap.on("removeClick",()=>{
            maplibreMap.off("click",(ev:MapMouseEvent)=>{onMapClick(ev,maplibreMap)})
        })
    },[onMapClick,isMapLoaded])

    useEffect(()=>{
        if(!onMapDoubleClick || !isMapLoaded) return
        maplibreMap.fire("removeDblclick")
        maplibreMap.on("dblclick",(ev:MapMouseEvent)=>{onMapDoubleClick(ev,maplibreMap)})
        maplibreMap.on("removeDblclick",()=>{
            maplibreMap.off("dblclick",(ev:MapMouseEvent)=>{onMapDoubleClick(ev,maplibreMap)})
        })
    },[onMapDoubleClick,isMapLoaded])

    useEffect(()=>{
        if(!onMapContextMenu || !isMapLoaded) return
        maplibreMap.fire("removeContextmenu")
        maplibreMap.on("contextmenu",(ev:MapMouseEvent)=>{onMapContextMenu(ev,maplibreMap)})
        maplibreMap.on("removeContextmenu",()=>{
            maplibreMap.off("contextmenu",(ev:MapMouseEvent)=>{onMapContextMenu(ev,maplibreMap)})
        })
    },[onMapContextMenu,isMapLoaded])

    return <div className={className} style={style}>
            <div ref={mapContainerRef} style={{ position: "absolute", width: "100%", height: "100%" }}>
                {children}
            </div>
        </div>
}

export default Maplibre